    #     "always_suppress": [],          # 항상 억제 노드 목록
    #     "modifier_bounds": {            # 각 modifier의 허용 범위
    #         "creativity": [0.1, 0.95],
    #         "risk_tolerance": [0.0, 0.8],
    #     },
    #     "immune_nodes": [],             # Immune Zone: 발현 변경 불가 노드
